import{_ as e,o as t,c as r,a4 as s}from"./chunks/framework.DyvFOq6U.js";const u=JSON.parse('{"title":"教學指南 / Tutorial Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":null}'),i={name:"guide/index.md"};function l(o,a,p,d,n,c){return t(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="教學指南-tutorial-guide" tabindex="-1">教學指南 / Tutorial Guide <a class="header-anchor" href="#教學指南-tutorial-guide" aria-label="Permalink to &quot;教學指南 / Tutorial Guide&quot;">​</a></h1><p>歡迎來到 Typst 練習場的教學指南！以下章節將帶你一步步學習 Typst 的基礎知識。每個章節都提供繁體中文與英文雙語說明，並附有練習題。</p><p>Welcome to the Typst Practice tutorial guide! The following chapters will guide you step-by-step through the basics of Typst. Each chapter provides bilingual Traditional Chinese and English explanations, along with practice exercises.</p><h2 id="學習章節-chapters" tabindex="-1">學習章節 / Chapters <a class="header-anchor" href="#學習章節-chapters" aria-label="Permalink to &quot;學習章節 / Chapters&quot;">​</a></h2><div class="feature-grid"><div class="feature-card"><h3>快速入門 / Quick Start</h3><p>了解 Typst 基本概念，建立第一份文件。</p><a href="/guide/quick-start" class="tag">開始學習 →</a></div><div class="feature-card"><h3>頁面設置 / Page Setup</h3><p>設定頁面大小、邊距、方向與編號。</p><a href="/guide/page-setup" class="tag">開始學習 →</a></div><div class="feature-card"><h3>文字與格式 / Text &amp; Formatting</h3><p>掌握文字樣式、字型、顏色、段落格式。</p><a href="/guide/text-formatting" class="tag">開始學習 →</a></div><div class="feature-card"><h3>插入圖片 / Images</h3><p>插入圖片、調整大小、設定標題與對齊。</p><a href="/guide/images" class="tag">開始學習 →</a></div><div class="feature-card"><h3>表格製作 / Tables</h3><p>建立表格、設定欄寬、合併儲存格、自訂樣式。</p><a href="/guide/tables" class="tag">開始學習 →</a></div><div class="feature-card"><h3>數學公式 / Math</h3><p>撰寫行內公式、獨立公式、對齊、矩陣等。</p><a href="/guide/math-basics" class="tag">開始學習 →</a></div><div class="feature-card"><h3>指令碼基礎 / Scripting Intro</h3><p>使用變數、條件判斷、迴圈和函數。</p><a href="/guide/scripting-intro" class="tag">開始學習 →</a></div></div><h2 id="前置準備-prerequisites" tabindex="-1">前置準備 / Prerequisites <a class="header-anchor" href="#前置準備-prerequisites" aria-label="Permalink to &quot;前置準備 / Prerequisites&quot;">​</a></h2><div class="bilingual-block"><div class="zh-block"><span class="lang-label">中文</span><p>學習本教程，你不需要安裝任何軟體！你可以：</p><ol><li>使用本網站的 <strong><a href="/sandbox/">互動沙盒</a></strong> 直接在瀏覽器中撰寫和預覽 Typst 程式碼</li><li>或者使用 <a href="https://typst.app/play/" target="_blank" rel="noreferrer">Typst 線上編輯器</a>（免費註冊）</li></ol><p>當然，如果你想在本地使用 Typst，可以從 <a href="https://typst.app/open-source/#download" target="_blank" rel="noreferrer">官方下載頁面</a> 下載 Typst CLI。</p></div><div class="en-block"><span class="lang-label">English</span><p>You don&#39;t need to install any software to follow this tutorial! You can:</p><ol><li>Use the <strong><a href="/sandbox/">Interactive Sandbox</a></strong> on this site to write and preview Typst code directly in your browser</li><li>Or use the <a href="https://typst.app/play/" target="_blank" rel="noreferrer">Typst online editor</a> (free sign-up)</li></ol><p>Of course, if you want to use Typst locally, you can download the Typst CLI from the <a href="https://typst.app/open-source/#download" target="_blank" rel="noreferrer">official download page</a>.</p></div></div>',7)])])}const g=e(i,[["render",l]]);export{u as __pageData,g as default};
